var pages_put_classification_level = &cobra.Command{
	Use:   "put-classification-level",
	Short: "Update page classification level",
	Long:  "Updates the [classification level](https://developer.atlassian.com/cloud/admin/dlp/rest/intro/#Classification%20level)\nfor a specific page.\n\n**[Permissions](https://confluence.atlassian.com/x/_AozKw) required**:\n'Permission to access the Confluence site ('Can use' global permission) and permission to edit the page.",
	RunE: func(cmd *cobra.Command, args []string) error {
		c, err := client.FromContext(cmd.Context())
		if err != nil {
			return err
		}
		id, _ := cmd.Flags().GetString("id")
		if strings.TrimSpace(id) == "" {
			apiErr := &cferrors.APIError{
				ErrorType: "validation_error",
				Message:   "--id must not be empty",
			}
			apiErr.WriteJSON(os.Stderr)
			return &cferrors.AlreadyWrittenError{Code: cferrors.ExitValidation}
		}
		path := fmt.Sprintf("/pages/%s/classification-level", url.PathEscape(id))
		query := client.QueryFromFlags(cmd)

		var bodyReader io.Reader
		bodyStr, _ := cmd.Flags().GetString("body")
		if bodyStr == "-" {
			bodyReader = os.Stdin
		} else if bodyStr != "" {
			if strings.HasPrefix(bodyStr, "@") {
				filename := strings.TrimPrefix(bodyStr, "@")
				if filename == "" {
					apiErr := &cferrors.APIError{
						ErrorType: "validation_error",
						Message:   "--body @<filename> requires a filename after @",
					}
					apiErr.WriteJSON(os.Stderr)
					return &cferrors.AlreadyWrittenError{Code: cferrors.ExitValidation}
				}
				f, err := os.Open(filename)
				if err != nil {
					apiErr := &cferrors.APIError{
						ErrorType: "validation_error",
						Message:   "cannot open body file: " + err.Error(),
					}
					apiErr.WriteJSON(os.Stderr)
					return &cferrors.AlreadyWrittenError{Code: cferrors.ExitValidation}
				}
				defer f.Close()
				bodyReader = f
			} else {
				bodyReader = strings.NewReader(bodyStr)
			}
		} else if !c.DryRun {
			// Check if stdin has data (guard against Stat failure to avoid nil dereference).
			// Skip in dry-run mode to avoid hanging on empty stdin pipes in non-terminal contexts.
			if stat, err := os.Stdin.Stat(); err == nil && (stat.Mode()&os.ModeCharDevice) == 0 {
				bodyReader = os.Stdin
			}
		}
		if bodyReader == nil && !c.DryRun {
			apiErr := &cferrors.APIError{
				ErrorType: "validation_error",
				Message:   "PUT request requires a body; use --body '{...}', --body @file, or pipe JSON to stdin",
			}
			apiErr.WriteJSON(os.Stderr)
			return &cferrors.AlreadyWrittenError{Code: cferrors.ExitValidation}
		}
		code := c.Do(cmd.Context(), "PUT", path, query, bodyReader)

		if code != 0 {
			return &cferrors.AlreadyWrittenError{Code: code}
		}
		return nil
	},
}

